 12→struct WindowConfig {
 13→    position_pref: String,
 14→}
 15→
 16→impl Default for WindowConfig {
 17→    fn default() -> Self {
 18→        Self {
 19→            position_pref: "top-third".to_string(),
 20→        }
 21→    }
 22→}
