 24→fn position_near_top(window: &tauri::WebviewWindow) {
 25→    let monitor = window
 26→        .current_monitor()
 27→        .ok()
 28→        .flatten()
 29→        .or_else(|| window.primary_monitor().ok().flatten());
 30→
 31→    if let Some(monitor) = monitor {
 32→        let monitor_size = monitor.size();
 33→        let monitor_pos = monitor.position();
 34→
 35→        if let Ok(window_size) = window.outer_size() {
 36→            let x = monitor_pos.x + (monitor_size.width as i32 - window_size.width as i32) / 2;
 37→            let y = monitor_pos.y + (monitor_size.height as i32) / 5;
 38→
 39→            if let Err(e) = window.set_position(tauri::PhysicalPosition::new(x, y)) {
 40→                eprintln!("failed to position window: {e}");
 41→            }
 42→        }
 43→    } else if let Err(e) = window.center() {
 44→        eprintln!("failed to center window: {e}");
 45→    }
 46→}
 47→
 48→fn show_and_focus(window: &tauri::WebviewWindow) {
 49→    let position_pref = window
 50→        .app_handle()
 51→        .try_state::<Mutex<WindowConfig>>()
 52→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 53→        .unwrap_or_else(|| "top-third".to_string());
 54→
 55→    if position_pref == "center" {
 56→        if let Err(e) = window.center() {
 57→            eprintln!("failed to center window: {e}");
 58→        }
 59→    } else {
 60→        position_near_top(window);
 61→    }
 62→
 63→    if let Err(e) = window.show() {
 64→        eprintln!("failed to show window: {e}");
 65→    }
 66→    if let Err(e) = window.set_focus() {
 67→        eprintln!("failed to focus window: {e}");
 68→    }
 69→}
 70→
 71→fn toggle_window(window: &tauri::WebviewWindow) {
 72→    let visible = window.is_visible().unwrap_or(false);
 73→    let focused = window.is_focused().unwrap_or(false);
 74→
 75→    if visible && focused {
 76→        if let Err(e) = window.hide() {
 77→            eprintln!("failed to hide window: {e}");
 78→        }
 79→    } else if visible {
 80→        show_and_focus(window);
 81→    } else {
 82→        show_and_focus(window);
 83→    }
 84→}
