 86→fn hash_string(s: &str) -> u64 {
 87→    let mut hasher = DefaultHasher::new();
 88→    s.hash(&mut hasher);
 89→    hasher.finish()
 90→}
 91→
 92→fn detect_content_type(content: &str) -> &'static str {
 93→    let trimmed = content.trim();
 94→
 95→    if trimmed.starts_with("http://") || trimmed.starts_with("https://") {
 96→        return "link";
 97→    }
 98→
 99→    if (trimmed.len() == 4 || trimmed.len() == 7 || trimmed.len() == 9)
100→        && trimmed.starts_with('#')
101→        && trimmed[1..].chars().all(|c| c.is_ascii_hexdigit())
102→    {
103→        return "color";
104→    }
105→
106→    if trimmed.starts_with("rgb(")
107→        || trimmed.starts_with("rgba(")
108→        || trimmed.starts_with("hsl(")
109→        || trimmed.starts_with("hsla(")
110→    {
111→        return "color";
112→    }
113→
114→    "text"
115→}
