117→fn start_clipboard_monitor(app_handle: tauri::AppHandle) {
118→    use tauri_plugin_clipboard_manager::ClipboardExt;
119→
120→    std::thread::spawn(move || {
121→        let mut last_hash: u64 = 0;
122→
123→        loop {
124→            std::thread::sleep(Duration::from_millis(500));
125→
126→            let text = match app_handle.clipboard().read_text() {
127→                Ok(t) => t,
128→                Err(_) => continue,
129→            };
130→
131→            if text.is_empty() {
132→                continue;
133→            }
134→
135→            let current_hash = hash_string(&text);
136→            if current_hash == last_hash {
137→                continue;
138→            }
139→            last_hash = current_hash;
140→
141→            let content_type = detect_content_type(&text);
142→
143→            let payload = serde_json::json!({
144→                "content": text,
145→                "contentType": content_type,
146→                "timestamp": std::time::SystemTime::now()
147→                    .duration_since(std::time::UNIX_EPOCH)
148→                    .unwrap_or_default()
149→                    .as_millis() as u64,
150→            });
151→
152→            if let Err(e) = app_handle.emit("clipboard-changed", payload) {
153→                eprintln!("failed to emit clipboard-changed: {e}");
154→            }
155→        }
156→    });
157→}
