159→#[tauri::command]
160→fn set_window_position_pref(
161→    state: tauri::State<'_, Mutex<WindowConfig>>,
162→    position: String,
163→) -> Result<(), String> {
164→    match position.as_str() {
165→        "center" | "top-third" => {
166→            if let Ok(mut config) = state.lock() {
167→                config.position_pref = position;
168→                Ok(())
169→            } else {
170→                Err("failed to acquire config lock".to_string())
171→            }
172→        }
173→        _ => Err(format!("invalid position: {position}")),
174→    }
175→}
