236→                    app,
237→                    "check-updates",
238→                    "Check for Updates",
239→                    true,
240→                    None::<&str>,
241→                )?;
242→                let about_item =
243→                    MenuItem::with_id(app, "about", "About Raycast Clone", true, None::<&str>)?;
244→                let quit_item = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
245→
246→                let menu = Menu::with_items(
