  1→import { useCallback, useEffect, useRef, useState } from 'react';
  2→import type { ClipboardEntry } from '../data/clipboard_data';
  3→import { MOCK_CLIPBOARD_ENTRIES } from '../data/clipboard_data';
  4→import type { ClipboardChangeEvent } from '../platform';
  5→import { getPlatform, isTauri } from '../platform';
  6→import { storageGet, storageSet } from '../utils/storage';
  7→
  8→const HISTORY_KEY = 'clipboard-history';
  9→const MAX_ENTRIES = 1000;
 10→
 11→interface StoredEntry {
 12→  id: string;
 13→  content: string;
 14→  contentType: 'text' | 'link' | 'color' | 'image';
 15→  sourceApp: string;
 16→  copiedAt: string;
 17→  pinned: boolean;
 18→}
 19→
 20→function isStoredEntryArray(value: unknown): value is StoredEntry[] {
 21→  if (!Array.isArray(value)) return false;
 22→  return value.every(
 23→    v =>
 24→      typeof v === 'object' &&
 25→      v !== null &&
 26→      typeof (v as StoredEntry).id === 'string' &&
 27→      typeof (v as StoredEntry).content === 'string' &&
 28→      typeof (v as StoredEntry).contentType === 'string' &&
 29→      typeof (v as StoredEntry).copiedAt === 'string' &&
 30→      typeof (v as StoredEntry).pinned === 'boolean',
 31→  );
 32→}
 33→
 34→function serializeEntries(entries: ClipboardEntry[]): StoredEntry[] {
 35→  return entries.map(e => ({
 36→    id: e.id,
 37→    content: e.content,
 38→    contentType: e.contentType,
 39→    sourceApp: e.sourceApp,
 40→    copiedAt: e.copiedAt.toISOString(),
 41→    pinned: e.pinned,
 42→  }));
 43→}
 44→
 45→function deserializeEntries(stored: StoredEntry[]): ClipboardEntry[] {
 46→  return stored.map(e => {
 47→    const date = new Date(e.copiedAt);
 48→    return {
 49→      id: e.id,
 50→      content: e.content,
 51→      contentType: e.contentType,
 52→      sourceApp: e.sourceApp,
 53→      sourceIcon: null,
 54→      copiedAt: isNaN(date.getTime()) ? new Date() : date,
 55→      pinned: e.pinned,
 56→    };
 57→  });
 58→}
 59→
 60→function loadEntries(): ClipboardEntry[] {
 61→  const stored = storageGet(HISTORY_KEY, isStoredEntryArray);
 62→  if (stored && stored.length > 0) {
 63→    return deserializeEntries(stored);
 64→  }
 65→  if (!isTauri) {
 66→    return MOCK_CLIPBOARD_ENTRIES.map(e => ({ ...e }));
 67→  }
 68→  return [];
 69→}
 70→
 71→function persistEntries(entries: ClipboardEntry[]) {
 72→  storageSet(HISTORY_KEY, serializeEntries(entries));
 73→}
 74→
 75→function createEntryFromEvent(event: ClipboardChangeEvent): ClipboardEntry {
 76→  return {
 77→    id: `clip-${event.timestamp}-${Math.random().toString(36).slice(2, 8)}`,
 78→    content: event.content,
 79→    contentType: event.contentType,
 80→    sourceApp: 'System',
 81→    sourceIcon: null,
 82→    copiedAt: new Date(event.timestamp),
 83→    pinned: false,
 84→  };
 85→}
 86→
 87→export function useClipboardHistory() {
 88→  const [entries, setEntries] = useState<ClipboardEntry[]>(loadEntries);
 89→  const entriesRef = useRef(entries);
 90→  entriesRef.current = entries;
 91→
 92→  useEffect(() => {
 93→    if (!isTauri) return;
 94→
 95→    let unsubscribe: (() => void) | undefined;
 96→    let cancelled = false;
 97→
 98→    getPlatform()
 99→      .clipboard.onClipboardChange((event: ClipboardChangeEvent) => {
100→        if (cancelled) return;
101→
102→        const isDuplicate = entriesRef.current.some(
103→          e => e.content === event.content && !e.pinned,
104→        );
105→
106→        setEntries(prev => {
107→          let next: ClipboardEntry[];
108→          if (isDuplicate) {
109→            const existing = prev.find(e => e.content === event.content);
110→            if (existing) {
111→              next = [
112→                {
113→                  ...existing,
114→                  copiedAt: new Date(event.timestamp),
115→                },
116→                ...prev.filter(e => e.id !== existing.id),
117→              ];
118→            } else {
119→              next = [
120→                createEntryFromEvent(event),
121→                ...prev,
122→              ];
123→            }
124→          } else {
125→            next = [
126→              createEntryFromEvent(event),
127→              ...prev,
128→            ];
129→          }
130→
131→          if (next.length > MAX_ENTRIES) {
132→            const pinned = next.filter(e => e.pinned);
133→            const unpinned = next.filter(e => !e.pinned);
134→            next = [
135→              ...pinned,
136→              ...unpinned.slice(0, MAX_ENTRIES - pinned.length),
137→            ];
138→          }
139→
140→          persistEntries(next);
141→          return next;
142→        });
143→      })
144→      .then(unsub => {
145→        if (cancelled) {
146→          unsub();
147→        } else {
148→          unsubscribe = unsub;
149→        }
150→      });
151→
152→    return () => {
153→      cancelled = true;
154→      unsubscribe?.();
155→    };
156→  }, []);
157→
158→  const togglePin = useCallback((entryId: string) => {
159→    setEntries(prev => {
160→      const next = prev.map(e =>
161→        e.id === entryId
162→          ? {
163→              ...e,
164→              pinned: !e.pinned,
165→            }
166→          : e);
167→      persistEntries(next);
168→      return next;
169→    });
170→  }, []);
171→
172→  const deleteEntry = useCallback((entryId: string) => {
173→    setEntries(prev => {
174→      const next = prev.filter(e => e.id !== entryId);
175→      persistEntries(next);
176→      return next;
177→    });
178→  }, []);
179→
180→  const clearAll = useCallback(() => {
181→    setEntries([]);
182→    persistEntries([]);
183→  }, []);
184→
185→  return {
186→    entries,
187→    togglePin,
188→    deleteEntry,
189→    clearAll,
190→  };
191→}
