38→const shell: PlatformShell = {
39→  async openUrl(url: string) {
40→    try {
41→      const parsed = new URL(url);
42→      if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
43→        return;
44→      }
45→    } catch {
46→      return;
47→    }
48→    window.open(url, '_blank', 'noopener,noreferrer');
49→  },
50→  async openDeepLink(url: string) {
51→    const anchor = document.createElement('a');
52→    anchor.href = url;
53→    anchor.click();
